SELECT ?employerLabel WHERE { 
  wd:Q442325 p:P108 ?stmt.
  ?stmt ps:P108 ?employer;
        pq:P582 ?endDate.

  wd:Q442325 p:P108 ?stmtUS.
  ?stmtUS ps:P108 wd:Q628233;
          pq:P580 ?usmntStartDate.

  FILTER (?endDate < ?usmntStartDate)

  ?employer rdfs:label ?employerLabel.
  FILTER (lang(?employerLabel) = "en")
}
ORDER BY DESC(?endDate)
LIMIT 1

